INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_201_a__c','FAR_5_201_a','5.201(a)','General.','Part 5 › Subpart 5.2 › 5.201 General. › (a)','(a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), agencies must make notices of proposed contract actions available as specified in paragraph (b) of this section.','Part 5 › Subpart 5.2 › 5.201 General. › (a) | (a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), agencies must make notices of proposed contract actions available as specified in paragraph (b) of this section.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_201_b__c','FAR_5_201_b','5.201(b)','General.','Part 5 › Subpart 5.2 › 5.201 General. › (b)','(1) For acquisitions of supplies and services, other than those covered by the exceptions in 5.202 and the special situations in 5.205, the contracting officer must transmit a notice to the GPE, for each proposed- (i) Contract action meeting the threshold in 5.101(a)(1); (ii) Modification to an existing contract for additional supplies or services that meets the threshold in 5.101(a)(1); or (iii) Contract action in any amount when advantageous to the Government. (2) When transmitting notices using electronic commerce, contracting officers must ensure the notice is forwarded to the GPE.','Part 5 › Subpart 5.2 › 5.201 General. › (b) | (1) For acquisitions of supplies and services, other than those covered by the exceptions in 5.202 and the special situations in 5.205, the contracting officer must transmit a notice to the GPE, for each proposed- (i) Contract action meeting the threshold in 5.101(a)(1); (ii) Modification to an existing contract for additional supplies or services that meets the threshold in 5.101(a)(1); or (iii) Contract action in any amount when advantageous to the Government. (2) When transmitting notices using electronic commerce, contracting officers must ensure the notice is forwarded to the GPE.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_201_c__c','FAR_5_201_c','5.201(c)','General.','Part 5 › Subpart 5.2 › 5.201 General. › (c)','(c) The primary purposes of the notice are to improve small business access to acquisition information and enhance competition by identifying contracting and subcontracting opportunities.','Part 5 › Subpart 5.2 › 5.201 General. › (c) | (c) The primary purposes of the notice are to improve small business access to acquisition information and enhance competition by identifying contracting and subcontracting opportunities.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_201_d__c','FAR_5_201_d','5.201(d)','General.','Part 5 › Subpart 5.2 › 5.201 General. › (d)','(d) The GPE may be accessed via the Internet at https://www.sam.gov.','Part 5 › Subpart 5.2 › 5.201 General. › (d) | (d) The GPE may be accessed via the Internet at https://www.sam.gov.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_201__c','FAR_5_201','5.201','General.','Part 5 › Subpart 5.2 › 5.201 General.','(a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), agencies must make notices of proposed contract actions available as specified in paragraph (b) of this section. (c) The primary purposes of the notice are to improve small business access to acquisition information and enhance competition by identifying contracting and subcontracting opportunities. (d) The GPE may be accessed via the Internet at https://www.sam.gov.','Part 5 › Subpart 5.2 › 5.201 General. | (a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), agencies must make notices of proposed contract actions available as specified in paragraph (b) of this section. (c) The primary purposes of the notice are to improve small business access to acquisition information and enhance competition by identifying contracting and subcontracting opportunities. (d) The GPE may be accessed via the Internet at https://www.sam.gov.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_202_a__c','FAR_5_202_a','5.202(a)','Exceptions.','Part 5 › Subpart 5.2 › 5.202 Exceptions. › (a)','(a) The contracting officer determines that- (1) The synopsis cannot be worded to preclude disclosure of an agency’s needs and such disclosure would compromise the national security (e.g., would result in disclosure of classified information). The fact that a proposed solicitation or contract action contains classified information, or that access to classified matter may be necessary to submit a proposal or perform the contract does not, in itself, justify use of this exception to synopsis; (2) The proposed contract action is made under the conditions described in 6.302-2 (or, for purchases conducted using simplified acquisition procedures, if unusual and compelling urgency precludes competition to the maximum extent practicable) and the Government would be seriously injured if the agency complies with the time periods specified in 5.203; (3) The proposed contract action is one for which either the written direction of a foreign government reimbursing the agency for the cost of the acquisition of the supplies or services for such government, or the terms of an international agreement or treaty between the United States and a foreign government, or international organizations, has the effect of requiring that the acquisition shall be from specified sources; (4) The proposed contract action is expressly authorized or required by a statute to be made through another Government agency, including acquisitions from the Small Business Administration (SBA) using the authority of section 8(a) of the Small Business Act (but see 5.205(f)), or from a specific source such as a workshop for the blind under the rules of the Committee for Purchase from People Who Are Blind or Severely Disabled; (5) The proposed contract action is for utility services other than telecommunications services and only one source is available; (6) The proposed contract action is an order placed under subpart 16.5. When the order contains brand-name specifications, see especially 16.505(a)(4); (7) The proposed contract action results from acceptance of a proposal under the Small Business Innovation Development Act of1982 (Pub.L.97-219); (8) The proposed contract action results from the acceptance of an unsolicited research proposal that demonstrates a unique and innovative concept (see 2.101) and publication of any notice complying with 5.207 would improperly disclose the originality of thought or innovativeness of the proposed research, or would disclose proprietary information associated with the proposal. This exception does not apply if the proposed contract action results from an unsolicited research proposal and acceptance is based solely upon the unique capability of the source to perform the particular research services proposed (see 6.302-1(a)(2)(i)); (9) The proposed contract action is made for perishable subsistence supplies, and advance notice is not appropriate or reasonable; (10) The proposed contract action is made under conditions described in 6.302-3, or 6.302-5 with regard to brand name commercial products for authorized resale, or 6.302-7, and advance notice is not appropriate or reasonable; (11) The proposed contract action is made under the terms of an existing contract that was previously synopsized in sufficient detail to comply with the requirements of 5.207 with respect to the current proposed contract action; (12) The proposed contract action is by a Defense agency and the proposed contract action will be made and performed outside the United States and its outlying areas, and only local sources will be solicited. This exception does not apply to proposed contract actions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4); (13) The proposed contract action- (i) Is for an amount not expected to exceed the simplified acquisition threshold; (ii) Will be made through a means that provides access to the notice of proposed contract action through the GPE; and (iii) Permits the public to respond to the solicitation electronically; or (14) The proposed contract action is made under conditions described in 6.302-3 with respect to the services of an expert to support the Federal Government in any current or anticipated litigation or dispute.','Part 5 › Subpart 5.2 › 5.202 Exceptions. › (a) | (a) The contracting officer determines that- (1) The synopsis cannot be worded to preclude disclosure of an agency’s needs and such disclosure would compromise the national security (e.g., would result in disclosure of classified information). The fact that a proposed solicitation or contract action contains classified information, or that access to classified matter may be necessary to submit a proposal or perform the contract does not, in itself, justify use of this exception to synopsis; (2) The proposed contract action is made under the conditions described in 6.302-2 (or, for purchases conducted using simplified acquisition procedures, if unusual and compelling urgency precludes competition to the maximum extent practicable) and the Government would be seriously injured if the agency complies with the time periods specified in 5.203; (3) The proposed contract action is one for which either the written direction of a foreign government reimbursing the agency for the cost of the acquisition of the supplies or services for such government, or the terms of an international agreement or treaty between the United States and a foreign government, or international organizations, has the effect of requiring that the acquisition shall be from specified sources; (4) The proposed contract action is expressly authorized or required by a statute to be made through another Government agency, including acquisitions from the Small Business Administration (SBA) using the authority of section 8(a) of the Small Business Act (but see 5.205(f)), or from a specific source such as a workshop for the blind under the rules of the Committee for Purchase from People Who Are Blind or Severely Disabled; (5) The proposed contract action is for utility services other than telecommunications services and only one source is available; (6) The proposed contract action is an order placed under subpart 16.5. When the order contains brand-name specifications, see especially 16.505(a)(4); (7) The proposed contract action results from acceptance of a proposal under the Small Business Innovation Development Act of1982 (Pub.L.97-219); (8) The proposed contract action results from the acceptance of an unsolicited research proposal that demonstrates a unique and innovative concept (see 2.101) and publication of any notice complying with 5.207 would improperly disclose the originality of thought or innovativeness of the proposed research, or would disclose proprietary information associated with the proposal. This exception does not apply if the proposed contract action results from an unsolicited research proposal and acceptance is based solely upon the unique capability of the source to perform the particular research services proposed (see 6.302-1(a)(2)(i)); (9) The proposed contract action is made for perishable subsistence supplies, and advance notice is not appropriate or reasonable; (10) The proposed contract action is made under conditions described in 6.302-3, or 6.302-5 with regard to brand name commercial products for authorized resale, or 6.302-7, and advance notice is not appropriate or reasonable; (11) The proposed contract action is made under the terms of an existing contract that was previously synopsized in sufficient detail to comply with the requirements of 5.207 with respect to the current proposed contract action; (12) The proposed contract action is by a Defense agency and the proposed contract action will be made and performed outside the United States and its outlying areas, and only local sources will be solicited. This exception does not apply to proposed contract actions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4); (13) The proposed contract action- (i) Is for an amount not expected to exceed the simplified acquisition threshold; (ii) Will be made through a means that provides access to the notice of proposed contract action through the GPE; and (iii) Permits the public to respond to the solicitation electronically; or (14) The proposed contract action is made under conditions described in 6.302-3 with respect to the services of an expert to support the Federal Government in any current or anticipated litigation or dispute.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_202_b__c','FAR_5_202_b','5.202(b)','Exceptions.','Part 5 › Subpart 5.2 › 5.202 Exceptions. › (b)','(b) The head of the agency determines in writing, after consultation with the Administrator for Federal Procurement Policy and the Administrator of the Small Business Administration, that advance notice is not appropriate or reasonable.','Part 5 › Subpart 5.2 › 5.202 Exceptions. › (b) | (b) The head of the agency determines in writing, after consultation with the Administrator for Federal Procurement Policy and the Administrator of the Small Business Administration, that advance notice is not appropriate or reasonable.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_202__c','FAR_5_202','5.202','Exceptions.','Part 5 › Subpart 5.2 › 5.202 Exceptions.','The contracting officer need not submit the notice required by 5.201 when- (a) The contracting officer determines that- (b) The head of the agency determines in writing, after consultation with the Administrator for Federal Procurement Policy and the Administrator of the Small Business Administration, that advance notice is not appropriate or reasonable.','Part 5 › Subpart 5.2 › 5.202 Exceptions. | The contracting officer need not submit the notice required by 5.201 when- (a) The contracting officer determines that- (b) The head of the agency determines in writing, after consultation with the Administrator for Federal Procurement Policy and the Administrator of the Small Business Administration, that advance notice is not appropriate or reasonable.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_a__c','FAR_5_203_a','5.203(a)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (a)','(a) An agency must transmit a notice of proposed contract action to the GPE (see 5.201). All publicizing and response times are calculated based on the date of publication. The publication date is the date the notice appears on the GPE. The notice must be published at least 15 days before issuance of a solicitation, or a proposed contract action the Government intends to solicit and negotiate with only one source under the authority of 6.302, except that, for acquisitions of commercial products or commercial services, the contracting officer may- (1) Establish a shorter period for issuance of the solicitation; or (2) Use the combined synopsis and solicitation procedure (see 12.603).','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (a) | (a) An agency must transmit a notice of proposed contract action to the GPE (see 5.201). All publicizing and response times are calculated based on the date of publication. The publication date is the date the notice appears on the GPE. The notice must be published at least 15 days before issuance of a solicitation, or a proposed contract action the Government intends to solicit and negotiate with only one source under the authority of 6.302, except that, for acquisitions of commercial products or commercial services, the contracting officer may- (1) Establish a shorter period for issuance of the solicitation; or (2) Use the combined synopsis and solicitation procedure (see 12.603).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_b__c','FAR_5_203_b','5.203(b)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (b)','(b) The contracting officer must establish a solicitation response time that will afford potential offerors a reasonable opportunity to respond to each proposed contract action, (including actions where the notice of proposed contract action and solicitation information is accessible through the GPE), in an amount estimated to be greater than $25,000, but not greater than the simplified acquisition threshold; or each contract action for the acquisition of commercial products or commercial services in an amount estimated to be greater than $25,000. The contracting officer should consider the circumstances of the individual acquisition, such as the complexity, commerciality, availability, and urgency, when establishing the solicitation response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (b) | (b) The contracting officer must establish a solicitation response time that will afford potential offerors a reasonable opportunity to respond to each proposed contract action, (including actions where the notice of proposed contract action and solicitation information is accessible through the GPE), in an amount estimated to be greater than $25,000, but not greater than the simplified acquisition threshold; or each contract action for the acquisition of commercial products or commercial services in an amount estimated to be greater than $25,000. The contracting officer should consider the circumstances of the individual acquisition, such as the complexity, commerciality, availability, and urgency, when establishing the solicitation response time.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_c__c','FAR_5_203_c','5.203(c)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (c)','(c) Except for the acquisition of commercial products or commercial services (see 5.203(b)), agencies shall allow at least a 30-day response time for receipt of bids or proposals from the date of issuance of a solicitation, if the proposed contract action is expected to exceed the simplified acquisition threshold.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (c) | (c) Except for the acquisition of commercial products or commercial services (see 5.203(b)), agencies shall allow at least a 30-day response time for receipt of bids or proposals from the date of issuance of a solicitation, if the proposed contract action is expected to exceed the simplified acquisition threshold.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_d__c','FAR_5_203_d','5.203(d)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (d)','(d) Agencies shall allow at least a 30 day response time from the date of publication of a proper notice of intent to contract for architect-engineer services or before issuance of an order under a basic ordering agreement or similar arrangement if the proposed contract action is expected to exceed the simplified acquisition threshold.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (d) | (d) Agencies shall allow at least a 30 day response time from the date of publication of a proper notice of intent to contract for architect-engineer services or before issuance of an order under a basic ordering agreement or similar arrangement if the proposed contract action is expected to exceed the simplified acquisition threshold.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_e__c','FAR_5_203_e','5.203(e)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (e)','(e) Agencies must allow at least a 45-day response time for receipt of bids or proposals from the date of publication of the notice required in 5.201 for proposed contract actions categorized as research and development if the proposed contract action is expected to exceed the simplified acquisition threshold.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (e) | (e) Agencies must allow at least a 45-day response time for receipt of bids or proposals from the date of publication of the notice required in 5.201 for proposed contract actions categorized as research and development if the proposed contract action is expected to exceed the simplified acquisition threshold.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_f__c','FAR_5_203_f','5.203(f)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (f)','(f) Nothing in this subpart prohibits officers or employees of agencies from responding to requests for information.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (f) | (f) Nothing in this subpart prohibits officers or employees of agencies from responding to requests for information.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_g__c','FAR_5_203_g','5.203(g)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (g)','(g) Contracting officers may, unless they have evidence to the contrary, presume the notice was published oneday after transmission to the GPE. This presumption does not negate the mandatory waiting or response times specified in paragraphs (a) through (d) of this section. Upon learning that a particular notice has not in fact been published within the presumed timeframes, contracting officers should consider whether the date for receipt of offers can be extended or whether circumstances have become sufficiently compelling to justify proceeding with the proposed contract action under the authority of 5.202(a)(2).','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (g) | (g) Contracting officers may, unless they have evidence to the contrary, presume the notice was published oneday after transmission to the GPE. This presumption does not negate the mandatory waiting or response times specified in paragraphs (a) through (d) of this section. Upon learning that a particular notice has not in fact been published within the presumed timeframes, contracting officers should consider whether the date for receipt of offers can be extended or whether circumstances have become sufficiently compelling to justify proceeding with the proposed contract action under the authority of 5.202(a)(2).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203_h__c','FAR_5_203_h','5.203(h)','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (h)','(h) In addition to other requirements set forth in this section, for acquisitions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4), the period of time between publication of the synopsis notice and receipt of offers must be no less than 40 days. However, if the acquisition falls within a general category identified in an annual forecast, the availability of which is published, the contracting officer may reduce this time period to as few as 10 days.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. › (h) | (h) In addition to other requirements set forth in this section, for acquisitions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4), the period of time between publication of the synopsis notice and receipt of offers must be no less than 40 days. However, if the acquisition falls within a general category identified in an annual forecast, the availability of which is published, the contracting officer may reduce this time period to as few as 10 days.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_203__c','FAR_5_203','5.203','Publicizing and response time.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time.','Whenever agencies are required to publicize notice of proposed contract actions under 5.201, they must proceed as follows: (a) An agency must transmit a notice of proposed contract action to the GPE (see 5.201). All publicizing and response times are calculated based on the date of publication. The publication date is the date the notice appears on the GPE. The notice must be published at least 15 days before issuance of a solicitation, or a proposed contract action the Government intends to solicit and negotiate with only one source under the authority of 6.302, except that, for acquisitions of commercial products or commercial services, the contracting officer may- (b) The contracting officer must establish a solicitation response time that will afford potential offerors a reasonable opportunity to respond to each proposed contract action, (including actions where the notice of proposed contract action and solicitation information is accessible through the GPE), in an amount estimated to be greater than $25,000, but not greater than the simplified acquisition threshold; or each contract action for the acquisition of commercial products or commercial services in an amount estimated to be greater than $25,000. The contracting officer should consider the circumstances of the individual acquisition, such as the complexity, commerciality, availability, and urgency, when establishing the solicitation response time. (c) Except for the acquisition of commercial products or commercial services (see 5.203(b)), agencies shall allow at least a 30-day response time for receipt of bids or proposals from the date of issuance of a solicitation, if the proposed contract action is expected to exceed the simplified acquisition threshold. (d) Agencies shall allow at least a 30 day response time from the date of publication of a proper notice of intent to contract for architect-engineer services or before issuance of an order under a basic ordering agreement or similar arrangement if the proposed contract action is expected to exceed the simplified acquisition threshold. (e) Agencies must allow at least a 45-day response time for receipt of bids or proposals from the date of publication of the notice required in 5.201 for proposed contract actions categorized as research and development if the proposed contract action is expected to exceed the simplified acquisition threshold. (f) Nothing in this subpart prohibits officers or employees of agencies from responding to requests for information. (g) Contracting officers may, unless they have evidence to the contrary, presume the notice was published oneday after transmission to the GPE. This presumption does not negate the mandatory waiting or response times specified in paragraphs (a) through (d) of this section. Upon learning that a particular notice has not in fact been published within the presumed timeframes, contracting officers should consider whether the date for receipt of offers can be extended or whether circumstances have become sufficiently compelling to justify proceeding with the proposed contract action under the authority of 5.202(a)(2). (h) In addition to other requirements set forth in this section, for acquisitions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4), the period of time between publication of the synopsis notice and receipt of offers must be no less than 40 days. However, if the acquisition falls within a general category identified in an annual forecast, the availability of which is published, the contracting officer may reduce this time period to as few as 10 days.','Part 5 › Subpart 5.2 › 5.203 Publicizing and response time. | Whenever agencies are required to publicize notice of proposed contract actions under 5.201, they must proceed as follows: (a) An agency must transmit a notice of proposed contract action to the GPE (see 5.201). All publicizing and response times are calculated based on the date of publication. The publication date is the date the notice appears on the GPE. The notice must be published at least 15 days before issuance of a solicitation, or a proposed contract action the Government intends to solicit and negotiate with only one source under the authority of 6.302, except that, for acquisitions of commercial products or commercial services, the contracting officer may- (b) The contracting officer must establish a solicitation response time that will afford potential offerors a reasonable opportunity to respond to each proposed contract action, (including actions where the notice of proposed contract action and solicitation information is accessible through the GPE), in an amount estimated to be greater than $25,000, but not greater than the simplified acquisition threshold; or each contract action for the acquisition of commercial products or commercial services in an amount estimated to be greater than $25,000. The contracting officer should consider the circumstances of the individual acquisition, such as the complexity, commerciality, availability, and urgency, when establishing the solicitation response time. (c) Except for the acquisition of commercial products or commercial services (see 5.203(b)), agencies shall allow at least a 30-day response time for receipt of bids or proposals from the date of issuance of a solicitation, if the proposed contract action is expected to exceed the simplified acquisition threshold. (d) Agencies shall allow at least a 30 day response time from the date of publication of a proper notice of intent to contract for architect-engineer services or before issuance of an order under a basic ordering agreement or similar arrangement if the proposed contract action is expected to exceed the simplified acquisition threshold. (e) Agencies must allow at least a 45-day response time for receipt of bids or proposals from the date of publication of the notice required in 5.201 for proposed contract actions categorized as research and development if the proposed contract action is expected to exceed the simplified acquisition threshold. (f) Nothing in this subpart prohibits officers or employees of agencies from responding to requests for information. (g) Contracting officers may, unless they have evidence to the contrary, presume the notice was published oneday after transmission to the GPE. This presumption does not negate the mandatory waiting or response times specified in paragraphs (a) through (d) of this section. Upon learning that a particular notice has not in fact been published within the presumed timeframes, contracting officers should consider whether the date for receipt of offers can be extended or whether circumstances have become sufficiently compelling to justify proceeding with the proposed contract action under the authority of 5.202(a)(2). (h) In addition to other requirements set forth in this section, for acquisitions covered by the World Trade Organization Government Procurement Agreement or a Free Trade Agreement (see subpart 25.4), the period of time between publication of the synopsis notice and receipt of offers must be no less than 40 days. However, if the acquisition falls within a general category identified in an annual forecast, the availability of which is published, the contracting officer may reduce this time period to as few as 10 days.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_a__c','FAR_5_205_a','5.205(a)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (a)','(a) Research and development (R&D) advance notices. Contracting officers may transmit to the GPE advance notices of their interest in potential R&D programs whenever market research does not produce a sufficient number of concerns to obtain adequate competition. Advance notices must not be used where security considerations prohibit such publication. Advance notices will enable potential sources to learn of R&D programs and provide these sources with an opportunity to submit information which will permit evaluation of their capabilities. Contracting officers must consider potential sources which respond to advance notices for a subsequent solicitation. Advanced notices must be entitled "Research and Development Sources Sought" and include the name and telephone number of the contracting officer or other contracting activity official from whom technical details of the project can be obtained. This will enable sources to submit information for evaluation of their R&D capabilities. Contracting officers must synopsize (see 5.201) all subsequent solicitations for R&D contracts, including those resulting from a previously synopsized advance notice, unless one of the exceptions in 5.202 applies.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (a) | (a) Research and development (R&D) advance notices. Contracting officers may transmit to the GPE advance notices of their interest in potential R&D programs whenever market research does not produce a sufficient number of concerns to obtain adequate competition. Advance notices must not be used where security considerations prohibit such publication. Advance notices will enable potential sources to learn of R&D programs and provide these sources with an opportunity to submit information which will permit evaluation of their capabilities. Contracting officers must consider potential sources which respond to advance notices for a subsequent solicitation. Advanced notices must be entitled "Research and Development Sources Sought" and include the name and telephone number of the contracting officer or other contracting activity official from whom technical details of the project can be obtained. This will enable sources to submit information for evaluation of their R&D capabilities. Contracting officers must synopsize (see 5.201) all subsequent solicitations for R&D contracts, including those resulting from a previously synopsized advance notice, unless one of the exceptions in 5.202 applies.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_b__c','FAR_5_205_b','5.205(b)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (b)','(b) Federally Funded Research and Development Centers. Before establishing a Federally Funded Research and Development Center (FFRDC) (see part 35) or before changing its basic purpose and mission, the sponsor must transmit at least three notices over a 90-day period to the GPE and the Federal Register, indicating the agency’s intention to sponsor an FFRDC or change the basic purpose and mission of an FFRDC. The notice must indicate the scope and nature of the effort to be performed and request comments. Notice is not required where the action is required by law.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (b) | (b) Federally Funded Research and Development Centers. Before establishing a Federally Funded Research and Development Center (FFRDC) (see part 35) or before changing its basic purpose and mission, the sponsor must transmit at least three notices over a 90-day period to the GPE and the Federal Register, indicating the agency’s intention to sponsor an FFRDC or change the basic purpose and mission of an FFRDC. The notice must indicate the scope and nature of the effort to be performed and request comments. Notice is not required where the action is required by law.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_c__c','FAR_5_205_c','5.205(c)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (c)','(c) Special notices. Contracting officers may transmit to the GPE special notices of procurement matters such as business fairs, long-range procurement estimates, prebid or preproposal conferences, meetings, and the availability of draft solicitations or draft specifications for review.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (c) | (c) Special notices. Contracting officers may transmit to the GPE special notices of procurement matters such as business fairs, long-range procurement estimates, prebid or preproposal conferences, meetings, and the availability of draft solicitations or draft specifications for review.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_d__c','FAR_5_205_d','5.205(d)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (d)','(d) Architect-engineering services. Contracting officers must publish notices of intent to contract for architect-engineering services as follows: (1) Except when exempted by 5.202, contracting officers must transmit to the GPE a synopsis of each proposed contract action for which the total fee (including phases and options) is expected to exceed $25,000. (2) When the total fee is expected to exceed $20,000 but not exceed $25,000, the contracting officer must comply with 5.101(a)(2). When the proposed contract action is not required to be synopsized under paragraph (d)(1) of this section, the contracting officer must display a notice of the solicitation or a copy of the solicitation in a public place at the contracting office. Other optional publicizing methods are authorized in accordance with 5.101(b).','Part 5 › Subpart 5.2 › 5.205 Special situations. › (d) | (d) Architect-engineering services. Contracting officers must publish notices of intent to contract for architect-engineering services as follows: (1) Except when exempted by 5.202, contracting officers must transmit to the GPE a synopsis of each proposed contract action for which the total fee (including phases and options) is expected to exceed $25,000. (2) When the total fee is expected to exceed $20,000 but not exceed $25,000, the contracting officer must comply with 5.101(a)(2). When the proposed contract action is not required to be synopsized under paragraph (d)(1) of this section, the contracting officer must display a notice of the solicitation or a copy of the solicitation in a public place at the contracting office. Other optional publicizing methods are authorized in accordance with 5.101(b).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_e__c','FAR_5_205_e','5.205(e)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (e)','(e) Public-private competitions under OMB Circular A-76. (1) The contracting officer shall make a formal public announcement for each streamlined or standard competition. The public announcement shall include, at a minimum, the agency, agency component, location, type of competition (streamlined or standard), activity being competed, incumbent service providers, number of Government personnel performing the activity, name of the Competitive Sourcing Official, name of the contracting officer, name of the Agency Tender Official, and projected end date of the competition. (2) The contracting officer shall announce the end of the streamlined or standard competition by making a formal public announcement of the performance decision. (See OMB Circular A-76.)','Part 5 › Subpart 5.2 › 5.205 Special situations. › (e) | (e) Public-private competitions under OMB Circular A-76. (1) The contracting officer shall make a formal public announcement for each streamlined or standard competition. The public announcement shall include, at a minimum, the agency, agency component, location, type of competition (streamlined or standard), activity being competed, incumbent service providers, number of Government personnel performing the activity, name of the Competitive Sourcing Official, name of the contracting officer, name of the Agency Tender Official, and projected end date of the competition. (2) The contracting officer shall announce the end of the streamlined or standard competition by making a formal public announcement of the performance decision. (See OMB Circular A-76.)');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_f__c','FAR_5_205_f','5.205(f)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (f)','(f) Section8(a) competitive acquisition. When a requirement is being considered for competitive acquisition limited to eligible 8(a) participants under subpart 19.8, the contracting officer must transmit a synopsis of the proposed contract action to the GPE. The synopsis may be transmitted to the GPE concurrent with submission of the agency offering (see 19.804-2) to the Small Business Administration (SBA). The synopsis should also include information- (1) Advising that the acquisition is being offered for competition limited to eligible 8(a) participants; (2) Specifying the North American Industry Classification System (NAICS) code; (3) Advising that eligibility to participate may be restricted to 8(a) participants in either the developmental stage or the developmental and transitional stages; and (4) Encouraging interested 8(a) participants to request a copy of the solicitation as expeditiously as possible since the solicitation will be issued without further notice upon SBA acceptance of the requirement for the section 8(a) program.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (f) | (f) Section8(a) competitive acquisition. When a requirement is being considered for competitive acquisition limited to eligible 8(a) participants under subpart 19.8, the contracting officer must transmit a synopsis of the proposed contract action to the GPE. The synopsis may be transmitted to the GPE concurrent with submission of the agency offering (see 19.804-2) to the Small Business Administration (SBA). The synopsis should also include information- (1) Advising that the acquisition is being offered for competition limited to eligible 8(a) participants; (2) Specifying the North American Industry Classification System (NAICS) code; (3) Advising that eligibility to participate may be restricted to 8(a) participants in either the developmental stage or the developmental and transitional stages; and (4) Encouraging interested 8(a) participants to request a copy of the solicitation as expeditiously as possible since the solicitation will be issued without further notice upon SBA acceptance of the requirement for the section 8(a) program.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_g__c','FAR_5_205_g','5.205(g)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (g)','(g) Notifications to the public regarding consolidation, bundling, or substantial bundling. (1) For the requirement to publish a notification of consolidation or substantial bundling of contract requirements, see 7.107-5(c) and (d). (2) The agency is encouraged to provide notification of the rationale for any bundled requirement to the GPE before issuing the solicitation of any bundled requirement (see 7.107-5(b)).','Part 5 › Subpart 5.2 › 5.205 Special situations. › (g) | (g) Notifications to the public regarding consolidation, bundling, or substantial bundling. (1) For the requirement to publish a notification of consolidation or substantial bundling of contract requirements, see 7.107-5(c) and (d). (2) The agency is encouraged to provide notification of the rationale for any bundled requirement to the GPE before issuing the solicitation of any bundled requirement (see 7.107-5(b)).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205_h__c','FAR_5_205_h','5.205(h)','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations. › (h)','(h) Notice regarding timely definitization of equitable adjustments for change orders under construction contracts. When the contracting officer anticipates award of a contract to a small business pursuant to a solicitation for construction, the contracting officer must transmit in the solicitation notice on the GPE information regarding definitization of equitable adjustments for change orders under construction contracts (see 36.211).','Part 5 › Subpart 5.2 › 5.205 Special situations. › (h) | (h) Notice regarding timely definitization of equitable adjustments for change orders under construction contracts. When the contracting officer anticipates award of a contract to a small business pursuant to a solicitation for construction, the contracting officer must transmit in the solicitation notice on the GPE information regarding definitization of equitable adjustments for change orders under construction contracts (see 36.211).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_205__c','FAR_5_205','5.205','Special situations.','Part 5 › Subpart 5.2 › 5.205 Special situations.','(a) Research and development (R&D) advance notices. Contracting officers may transmit to the GPE advance notices of their interest in potential R&D programs whenever market research does not produce a sufficient number of concerns to obtain adequate competition. Advance notices must not be used where security considerations prohibit such publication. Advance notices will enable potential sources to learn of R&D programs and provide these sources with an opportunity to submit information which will permit evaluation of their capabilities. Contracting officers must consider potential sources which respond to advance notices for a subsequent solicitation. Advanced notices must be entitled "Research and Development Sources Sought" and include the name and telephone number of the contracting officer or other contracting activity official from whom technical details of the project can be obtained. This will enable sources to submit information for evaluation of their R&D capabilities. Contracting officers must synopsize (see 5.201) all subsequent solicitations for R&D contracts, including those resulting from a previously synopsized advance notice, unless one of the exceptions in 5.202 applies. (b) Federally Funded Research and Development Centers. Before establishing a Federally Funded Research and Development Center (FFRDC) (see part 35) or before changing its basic purpose and mission, the sponsor must transmit at least three notices over a 90-day period to the GPE and the Federal Register, indicating the agency’s intention to sponsor an FFRDC or change the basic purpose and mission of an FFRDC. The notice must indicate the scope and nature of the effort to be performed and request comments. Notice is not required where the action is required by law. (c) Special notices. Contracting officers may transmit to the GPE special notices of procurement matters such as business fairs, long-range procurement estimates, prebid or preproposal conferences, meetings, and the availability of draft solicitations or draft specifications for review. (d) Architect-engineering services. Contracting officers must publish notices of intent to contract for architect-engineering services as follows: (e) Public-private competitions under OMB Circular A-76. (f) Section8(a) competitive acquisition. When a requirement is being considered for competitive acquisition limited to eligible 8(a) participants under subpart 19.8, the contracting officer must transmit a synopsis of the proposed contract action to the GPE. The synopsis may be transmitted to the GPE concurrent with submission of the agency offering (see 19.804-2) to the Small Business Administration (SBA). The synopsis should also include information- (g) Notifications to the public regarding consolidation, bundling, or substantial bundling. (h) Notice regarding timely definitization of equitable adjustments for change orders under construction contracts. When the contracting officer anticipates award of a contract to a small business pursuant to a solicitation for construction, the contracting officer must transmit in the solicitation notice on the GPE information regarding definitization of equitable adjustments for change orders under construction contracts (see 36.211).','Part 5 › Subpart 5.2 › 5.205 Special situations. | (a) Research and development (R&D) advance notices. Contracting officers may transmit to the GPE advance notices of their interest in potential R&D programs whenever market research does not produce a sufficient number of concerns to obtain adequate competition. Advance notices must not be used where security considerations prohibit such publication. Advance notices will enable potential sources to learn of R&D programs and provide these sources with an opportunity to submit information which will permit evaluation of their capabilities. Contracting officers must consider potential sources which respond to advance notices for a subsequent solicitation. Advanced notices must be entitled "Research and Development Sources Sought" and include the name and telephone number of the contracting officer or other contracting activity official from whom technical details of the project can be obtained. This will enable sources to submit information for evaluation of their R&D capabilities. Contracting officers must synopsize (see 5.201) all subsequent solicitations for R&D contracts, including those resulting from a previously synopsized advance notice, unless one of the exceptions in 5.202 applies. (b) Federally Funded Research and Development Centers. Before establishing a Federally Funded Research and Development Center (FFRDC) (see part 35) or before changing its basic purpose and mission, the sponsor must transmit at least three notices over a 90-day period to the GPE and the Federal Register, indicating the agency’s intention to sponsor an FFRDC or change the basic purpose and mission of an FFRDC. The notice must indicate the scope and nature of the effort to be performed and request comments. Notice is not required where the action is required by law. (c) Special notices. Contracting officers may transmit to the GPE special notices of procurement matters such as business fairs, long-range procurement estimates, prebid or preproposal conferences, meetings, and the availability of draft solicitations or draft specifications for review. (d) Architect-engineering services. Contracting officers must publish notices of intent to contract for architect-engineering services as follows: (e) Public-private competitions under OMB Circular A-76. (f) Section8(a) competitive acquisition. When a requirement is being considered for competitive acquisition limited to eligible 8(a) participants under subpart 19.8, the contracting officer must transmit a synopsis of the proposed contract action to the GPE. The synopsis may be transmitted to the GPE concurrent with submission of the agency offering (see 19.804-2) to the Small Business Administration (SBA). The synopsis should also include information- (g) Notifications to the public regarding consolidation, bundling, or substantial bundling. (h) Notice regarding timely definitization of equitable adjustments for change orders under construction contracts. When the contracting officer anticipates award of a contract to a small business pursuant to a solicitation for construction, the contracting officer must transmit in the solicitation notice on the GPE information regarding definitization of equitable adjustments for change orders under construction contracts (see 36.211).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_a__c','FAR_5_207_a','5.207(a)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (a)','(a) Content. Each synopsis transmitted to the GPE must address the following data elements, as applicable: (1) Action Code. (2) Date. (3) Year. (4) Contracting Office ZIP Code. (5) Product or Service Code. (6) Contracting Office Address. (7) Subject. (8) Proposed Solicitation Number. (9) Closing Response Date. (10) Contact Point or Contracting Officer. (11) Contract Award and Solicitation Number. (12) Contract Award Dollar Amount. (13) Line Item Number. (14) Contract Award Date. (15) Contractor. (16) Description. (17) Place of Contract Performance. (18) Set-aside Status.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (a) | (a) Content. Each synopsis transmitted to the GPE must address the following data elements, as applicable: (1) Action Code. (2) Date. (3) Year. (4) Contracting Office ZIP Code. (5) Product or Service Code. (6) Contracting Office Address. (7) Subject. (8) Proposed Solicitation Number. (9) Closing Response Date. (10) Contact Point or Contracting Officer. (11) Contract Award and Solicitation Number. (12) Contract Award Dollar Amount. (13) Line Item Number. (14) Contract Award Date. (15) Contractor. (16) Description. (17) Place of Contract Performance. (18) Set-aside Status.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_b__c','FAR_5_207_b','5.207(b)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (b)','(b) Transmittal. Transmissions to the GPE must be in accordance with the interface description available via the Internet at https://www.sam.gov.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (b) | (b) Transmittal. Transmissions to the GPE must be in accordance with the interface description available via the Internet at https://www.sam.gov.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_c__c','FAR_5_207_c','5.207(c)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (c)','(c) General format for "Description." Prepare a clear and concise description of the supplies or services that is not unnecessarily restrictive of competition and will allow a prospective offeror to make an informed business judgment as to whether a copy of the solicitation should be requested including the following, as appropriate: (1) National Stock Number (NSN) if assigned. (2) Specification and whether an offeror, its product, or service must meet a qualification requirement in order to be eligible for award, and identification of the office from which additional information about the qualification requirement may be obtained (see subpart 9.2). (3) Manufacturer, including part number, drawing number, etc. (4) Size, dimensions, or other form, fit or functional description. (5) Predominant material of manufacture. (6) Quantity, including any options for additional quantities. (7) Unit of issue. (8) Destination information. (9) Delivery schedule. (10) Duration of the contract period. (11) Sustainable acquisition requirements, such as a description of high-performance sustainable building practices required, if for design, construction, renovation, repair, or deconstruction (see part 23 and 36.104). (12) For a proposed contract action in an amount estimated to be greater than $25,000 but not greater than the simplified acquisition threshold, enter- (i) A description of the procedures to be used in awarding the contract (e.g., request for oral or written quotation or solicitation); and (ii) The anticipated award date. (13) For Architect-Engineer projects and other projects for which the product or service codes are insufficient, provide brief details with respect to: location, scope of services required, cost range and limitations, type of contract, estimated starting and completion dates, and any significant evaluation factors. (i) If the solicitation will include the FAR clause at 52.225-3, Buy American-Free Trade Agreements-Israeli Trade Act, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to Free Trade Agreements." (ii) If the solicitation will include the FAR clause at 52.225-5, Trade Agreements, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to the World Trade Organization Government Procurement Agreement and Free Trade Agreements." (iii) If the solicitation will include the FAR clause at 52.225-11, Buy American-Construction Materials under Trade Agreements, 52.225-23, Required Use of American Iron, Steel, and Manufactured Goods-Buy American Statute-Construction Materials under Trade Agreements, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to the World Trade Organization Government Procurement Agreement and Free Trade Agreements." (15) In the case of noncompetitive contract actions (including those that do not exceed the simplified acquisition threshold), identify the intended source and insert a statement of the reason justifying the lack of competition. (i) Except when using the sole source authority at 6.302-1, insert a statement that all responsible sources may submit a bid, proposal, or quotation which shall be considered by the agency. (ii) When using the sole source authority at 6.302-1, insert a statement that all responsible sources may submit a capability statement, proposal, or quotation, which shall be considered by the agency. (17) If solicitations synopsized through the GPE will not be made available through the GPE, provide information on how to obtain the solicitation. (18) If the solicitation will be made available to interested parties through electronic data interchange, provide any information necessary to obtain and respond to the solicitation electronically. (19) If the technical data required to respond to the solicitation will not be furnished as part of such solicitation, identify the source in the Government, such as https://www.sam.gov, from which the technical data may be obtained.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (c) | (c) General format for "Description." Prepare a clear and concise description of the supplies or services that is not unnecessarily restrictive of competition and will allow a prospective offeror to make an informed business judgment as to whether a copy of the solicitation should be requested including the following, as appropriate: (1) National Stock Number (NSN) if assigned. (2) Specification and whether an offeror, its product, or service must meet a qualification requirement in order to be eligible for award, and identification of the office from which additional information about the qualification requirement may be obtained (see subpart 9.2). (3) Manufacturer, including part number, drawing number, etc. (4) Size, dimensions, or other form, fit or functional description. (5) Predominant material of manufacture. (6) Quantity, including any options for additional quantities. (7) Unit of issue. (8) Destination information. (9) Delivery schedule. (10) Duration of the contract period. (11) Sustainable acquisition requirements, such as a description of high-performance sustainable building practices required, if for design, construction, renovation, repair, or deconstruction (see part 23 and 36.104). (12) For a proposed contract action in an amount estimated to be greater than $25,000 but not greater than the simplified acquisition threshold, enter- (i) A description of the procedures to be used in awarding the contract (e.g., request for oral or written quotation or solicitation); and (ii) The anticipated award date. (13) For Architect-Engineer projects and other projects for which the product or service codes are insufficient, provide brief details with respect to: location, scope of services required, cost range and limitations, type of contract, estimated starting and completion dates, and any significant evaluation factors. (i) If the solicitation will include the FAR clause at 52.225-3, Buy American-Free Trade Agreements-Israeli Trade Act, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to Free Trade Agreements." (ii) If the solicitation will include the FAR clause at 52.225-5, Trade Agreements, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to the World Trade Organization Government Procurement Agreement and Free Trade Agreements." (iii) If the solicitation will include the FAR clause at 52.225-11, Buy American-Construction Materials under Trade Agreements, 52.225-23, Required Use of American Iron, Steel, and Manufactured Goods-Buy American Statute-Construction Materials under Trade Agreements, or an equivalent agency clause, insert the following notice in the synopsis: "One or more of the items under this acquisition is subject to the World Trade Organization Government Procurement Agreement and Free Trade Agreements." (15) In the case of noncompetitive contract actions (including those that do not exceed the simplified acquisition threshold), identify the intended source and insert a statement of the reason justifying the lack of competition. (i) Except when using the sole source authority at 6.302-1, insert a statement that all responsible sources may submit a bid, proposal, or quotation which shall be considered by the agency. (ii) When using the sole source authority at 6.302-1, insert a statement that all responsible sources may submit a capability statement, proposal, or quotation, which shall be considered by the agency. (17) If solicitations synopsized through the GPE will not be made available through the GPE, provide information on how to obtain the solicitation. (18) If the solicitation will be made available to interested parties through electronic data interchange, provide any information necessary to obtain and respond to the solicitation electronically. (19) If the technical data required to respond to the solicitation will not be furnished as part of such solicitation, identify the source in the Government, such as https://www.sam.gov, from which the technical data may be obtained.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_d__c','FAR_5_207_d','5.207(d)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (d)','(d) Set-asides. When the proposed acquisition provides for a total or partial small business program set-aside, or when the proposed acquisition provides for a local area set-aside (see subpart 26.2), the contracting officer shall identify the type of set-aside in the synopsis and in the solicitation.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (d) | (d) Set-asides. When the proposed acquisition provides for a total or partial small business program set-aside, or when the proposed acquisition provides for a local area set-aside (see subpart 26.2), the contracting officer shall identify the type of set-aside in the synopsis and in the solicitation.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_e__c','FAR_5_207_e','5.207(e)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (e)','(e) Codes to be used in Synopses to identify services or supplies. Contracting officers must use one of the classification codes identified at https://www.sam.gov to identify services or supplies in synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (e) | (e) Codes to be used in Synopses to identify services or supplies. Contracting officers must use one of the classification codes identified at https://www.sam.gov to identify services or supplies in synopses.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207_f__c','FAR_5_207_f','5.207(f)','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (f)','(f) Notice of solicitation cancellation. Contracting officers may publish notices of solicitation cancellations (or indefinite suspensions) of proposed contract actions in the GPE.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. › (f) | (f) Notice of solicitation cancellation. Contracting officers may publish notices of solicitation cancellations (or indefinite suspensions) of proposed contract actions in the GPE.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_207__c','FAR_5_207','5.207','Preparation and transmittal of synopses.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses.','(a) Content. Each synopsis transmitted to the GPE must address the following data elements, as applicable: (b) Transmittal. Transmissions to the GPE must be in accordance with the interface description available via the Internet at https://www.sam.gov. (c) General format for "Description." Prepare a clear and concise description of the supplies or services that is not unnecessarily restrictive of competition and will allow a prospective offeror to make an informed business judgment as to whether a copy of the solicitation should be requested including the following, as appropriate: (d) Set-asides. When the proposed acquisition provides for a total or partial small business program set-aside, or when the proposed acquisition provides for a local area set-aside (see subpart 26.2), the contracting officer shall identify the type of set-aside in the synopsis and in the solicitation. (e) Codes to be used in Synopses to identify services or supplies. Contracting officers must use one of the classification codes identified at https://www.sam.gov to identify services or supplies in synopses. (f) Notice of solicitation cancellation. Contracting officers may publish notices of solicitation cancellations (or indefinite suspensions) of proposed contract actions in the GPE.','Part 5 › Subpart 5.2 › 5.207 Preparation and transmittal of synopses. | (a) Content. Each synopsis transmitted to the GPE must address the following data elements, as applicable: (b) Transmittal. Transmissions to the GPE must be in accordance with the interface description available via the Internet at https://www.sam.gov. (c) General format for "Description." Prepare a clear and concise description of the supplies or services that is not unnecessarily restrictive of competition and will allow a prospective offeror to make an informed business judgment as to whether a copy of the solicitation should be requested including the following, as appropriate: (d) Set-asides. When the proposed acquisition provides for a total or partial small business program set-aside, or when the proposed acquisition provides for a local area set-aside (see subpart 26.2), the contracting officer shall identify the type of set-aside in the synopsis and in the solicitation. (e) Codes to be used in Synopses to identify services or supplies. Contracting officers must use one of the classification codes identified at https://www.sam.gov to identify services or supplies in synopses. (f) Notice of solicitation cancellation. Contracting officers may publish notices of solicitation cancellations (or indefinite suspensions) of proposed contract actions in the GPE.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_12_603_a__c','FAR_12_603_a','12.603(a)','Streamlined solicitation for commercial products or commercial services.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (a)','(a) When a written solicitation will be issued, the contracting officer may use the following procedure to reduce the time required to solicit and award contracts for the acquisition of commercial products or commercial services. This procedure combines the synopsis required by 5.203 and the issuance of the solicitation into a single document.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (a) | (a) When a written solicitation will be issued, the contracting officer may use the following procedure to reduce the time required to solicit and award contracts for the acquisition of commercial products or commercial services. This procedure combines the synopsis required by 5.203 and the issuance of the solicitation into a single document.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_12_603_b__c','FAR_12_603_b','12.603(b)','Streamlined solicitation for commercial products or commercial services.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (b)','(b) When using the combined synopsis/solicitation procedure, the SF1449 is not used for issuing the solicitation.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (b) | (b) When using the combined synopsis/solicitation procedure, the SF1449 is not used for issuing the solicitation.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_12_603_c__c','FAR_12_603_c','12.603(c)','Streamlined solicitation for commercial products or commercial services.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (c)','(c) To use these procedures, the contracting officer shall- (1) Prepare the synopsis as described at 5.207. (2) In the Description, include the following additional information: (i) The following statement: (ii) The solicitation number and a statement that the solicitation is issued as an invitation to bid (IFB), request for quotation (RFQ) or request for proposal (RFP). (iii) A statement that the solicitation document and incorporated provisions and clauses are those in effect through Federal Acquisition Circular _____. (iv) A notice regarding any set-aside and the associated NAICS code and small business size standard. (v) A list of line item number(s) and items, quantities, and units of measure (including option(s), if applicable). (vi) Description of requirements for the items to be acquired. (vii) Date(s) and place(s) of delivery and acceptance and FOB point. (viii) A statement that the provision at 52.212-1, Instructions to Offerors-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding any addenda to the provision. (ix) A statement regarding the applicability of the provision at 52.212-2, Evaluation-Commercial Products and Commercial Services, if used, and the specific evaluation criteria to be included in paragraph (a) of that provision. If this provision is not used, describe the evaluation procedures to be used. (x) A statement advising offerors to include a completed copy of the provision at 52.212-3, Offeror Representations and Certifications-Commercial Products and Commercial Services, with its offer. (xi) A statement that the clause at 52.212-4, Contract Terms and Conditions-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding any addenda to the clause. (xii) A statement that the clause at 52.212-5, Contract Terms and Conditions Required To Implement Statutes or Executive Orders-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding which, if any, of the additional FAR clauses cited in the clause are applicable to the acquisition. (xiii) A statement regarding any additional contract requirement(s) or terms and conditions (such as contract financing arrangements or warranty requirements) determined by the contracting officer to be necessary for this acquisition and consistent with customary commercial practices. (xiv) A statement regarding the Defense Priorities and Allocations System (DPAS) and assigned rating, if applicable. (xv) The date, time and place offers are due. (xvi) The name and telephone number of the individual to contact for information regarding the solicitation. (3) Allow response time for receipt of offers as follows: (i) Because the synopsis and solicitation are contained in a single document, it is not necessary to publicize a separate synopsis 15 days before the issuance of the solicitation. (ii) When using the combined synopsis and solicitation, contracting officers must establish a response time in accordance with 5.203(b) (but see 5.203(h)). (4) Publicize amendments to solicitations in the same manner as the initial synopsis and solicitation.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. › (c) | (c) To use these procedures, the contracting officer shall- (1) Prepare the synopsis as described at 5.207. (2) In the Description, include the following additional information: (i) The following statement: (ii) The solicitation number and a statement that the solicitation is issued as an invitation to bid (IFB), request for quotation (RFQ) or request for proposal (RFP). (iii) A statement that the solicitation document and incorporated provisions and clauses are those in effect through Federal Acquisition Circular _____. (iv) A notice regarding any set-aside and the associated NAICS code and small business size standard. (v) A list of line item number(s) and items, quantities, and units of measure (including option(s), if applicable). (vi) Description of requirements for the items to be acquired. (vii) Date(s) and place(s) of delivery and acceptance and FOB point. (viii) A statement that the provision at 52.212-1, Instructions to Offerors-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding any addenda to the provision. (ix) A statement regarding the applicability of the provision at 52.212-2, Evaluation-Commercial Products and Commercial Services, if used, and the specific evaluation criteria to be included in paragraph (a) of that provision. If this provision is not used, describe the evaluation procedures to be used. (x) A statement advising offerors to include a completed copy of the provision at 52.212-3, Offeror Representations and Certifications-Commercial Products and Commercial Services, with its offer. (xi) A statement that the clause at 52.212-4, Contract Terms and Conditions-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding any addenda to the clause. (xii) A statement that the clause at 52.212-5, Contract Terms and Conditions Required To Implement Statutes or Executive Orders-Commercial Products and Commercial Services, applies to this acquisition and a statement regarding which, if any, of the additional FAR clauses cited in the clause are applicable to the acquisition. (xiii) A statement regarding any additional contract requirement(s) or terms and conditions (such as contract financing arrangements or warranty requirements) determined by the contracting officer to be necessary for this acquisition and consistent with customary commercial practices. (xiv) A statement regarding the Defense Priorities and Allocations System (DPAS) and assigned rating, if applicable. (xv) The date, time and place offers are due. (xvi) The name and telephone number of the individual to contact for information regarding the solicitation. (3) Allow response time for receipt of offers as follows: (i) Because the synopsis and solicitation are contained in a single document, it is not necessary to publicize a separate synopsis 15 days before the issuance of the solicitation. (ii) When using the combined synopsis and solicitation, contracting officers must establish a response time in accordance with 5.203(b) (but see 5.203(h)). (4) Publicize amendments to solicitations in the same manner as the initial synopsis and solicitation.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_12_603__c','FAR_12_603','12.603','Streamlined solicitation for commercial products or commercial services.','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services.','(a) When a written solicitation will be issued, the contracting officer may use the following procedure to reduce the time required to solicit and award contracts for the acquisition of commercial products or commercial services. This procedure combines the synopsis required by 5.203 and the issuance of the solicitation into a single document. (b) When using the combined synopsis/solicitation procedure, the SF1449 is not used for issuing the solicitation. (c) To use these procedures, the contracting officer shall-','Part 12 › Subpart 12.6 › 12.603 Streamlined solicitation for commercial products or commercial services. | (a) When a written solicitation will be issued, the contracting officer may use the following procedure to reduce the time required to solicit and award contracts for the acquisition of commercial products or commercial services. This procedure combines the synopsis required by 5.203 and the issuance of the solicitation into a single document. (b) When using the combined synopsis/solicitation procedure, the SF1449 is not used for issuing the solicitation. (c) To use these procedures, the contracting officer shall-');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_101_a__c','FAR_5_101_a','5.101(a)','Methods of disseminating information.','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information. › (a)','(a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), contracting officers must disseminate information on proposed contract actions as follows: (1) For proposed contract actions expected to exceed $25,000, by synopsizing in the GPE (see 5.201). (2) For proposed contract actions expected to exceed $20,000, but not expected to exceed $25,000, by displaying in a public place, or by any appropriate electronic means, an unclassified notice of the solicitation or a copy of the solicitation satisfying the requirements of 5.207(c). The notice must include a statement that all responsible sources may submit a response which, if timely received, must be considered by the agency. The information must be posted not later than the date the solicitation is issued, and must remain posted for at least 10 days or until after quotations have been opened, whichever is later. (i) If solicitations are posted instead of a notice, the contracting officer may employ various methods of satisfying the requirements of 5.207(c). For example, the contracting officer may meet the requirements of 5.207(c) by stamping the solicitation, by a cover sheet to the solicitation, or by placing a general statement in the display room. (ii) The contracting officer need not comply with the display requirements of this section when the exemptions at 5.202(a)(1), (a)(4) through (a)(9), or (a)(11) apply, when oral solicitations are used, or when providing access to a notice of proposed contract action and solicitation through the GPE and the notice permits the public to respond to the solicitation electronically. (iii) Contracting officers may use electronic posting of requirements in a place accessible by the general public at the Government installation to satisfy the public display requirement. Contracting offices using electronic systems for public posting that are not accessible outside the installation must periodically publicize the methods for accessing the information.','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information. › (a) | (a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), contracting officers must disseminate information on proposed contract actions as follows: (1) For proposed contract actions expected to exceed $25,000, by synopsizing in the GPE (see 5.201). (2) For proposed contract actions expected to exceed $20,000, but not expected to exceed $25,000, by displaying in a public place, or by any appropriate electronic means, an unclassified notice of the solicitation or a copy of the solicitation satisfying the requirements of 5.207(c). The notice must include a statement that all responsible sources may submit a response which, if timely received, must be considered by the agency. The information must be posted not later than the date the solicitation is issued, and must remain posted for at least 10 days or until after quotations have been opened, whichever is later. (i) If solicitations are posted instead of a notice, the contracting officer may employ various methods of satisfying the requirements of 5.207(c). For example, the contracting officer may meet the requirements of 5.207(c) by stamping the solicitation, by a cover sheet to the solicitation, or by placing a general statement in the display room. (ii) The contracting officer need not comply with the display requirements of this section when the exemptions at 5.202(a)(1), (a)(4) through (a)(9), or (a)(11) apply, when oral solicitations are used, or when providing access to a notice of proposed contract action and solicitation through the GPE and the notice permits the public to respond to the solicitation electronically. (iii) Contracting officers may use electronic posting of requirements in a place accessible by the general public at the Government installation to satisfy the public display requirement. Contracting offices using electronic systems for public posting that are not accessible outside the installation must periodically publicize the methods for accessing the information.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_101_b__c','FAR_5_101_b','5.101(b)','Methods of disseminating information.','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information. › (b)','(b) In addition, one or more of the following methods may be used: (1) Preparing periodic handouts listing proposed contracts, and displaying them as in 5.101(a)(2). (2) Assisting local trade associations in disseminating information to their members. (3) Making brief announcements of proposed contracts to newspapers, trade journals, magazines, or other mass communication media for publication without cost to the Government. (4) Placing paid advertisements in newspapers or other communications media, subject to the following limitations: (i) Contracting officers shall place paid advertisements of proposed contracts only when it is anticipated that effective competition cannot be obtained otherwise (see 5.205(d)). (ii) Contracting officers shall not place advertisements of proposed contracts in a newspaper published and printed in the District of Columbia unless the supplies or services will be furnished, or the labor performed, in the District of Columbia or adjoining counties in Maryland or Virginia (44 U.S.C. 3701). (iii) Advertisements published in newspapers must be under proper written authority in accordance with 44 U.S.C.3702 (see 5.502(a)).','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information. › (b) | (b) In addition, one or more of the following methods may be used: (1) Preparing periodic handouts listing proposed contracts, and displaying them as in 5.101(a)(2). (2) Assisting local trade associations in disseminating information to their members. (3) Making brief announcements of proposed contracts to newspapers, trade journals, magazines, or other mass communication media for publication without cost to the Government. (4) Placing paid advertisements in newspapers or other communications media, subject to the following limitations: (i) Contracting officers shall place paid advertisements of proposed contracts only when it is anticipated that effective competition cannot be obtained otherwise (see 5.205(d)). (ii) Contracting officers shall not place advertisements of proposed contracts in a newspaper published and printed in the District of Columbia unless the supplies or services will be furnished, or the labor performed, in the District of Columbia or adjoining counties in Maryland or Virginia (44 U.S.C. 3701). (iii) Advertisements published in newspapers must be under proper written authority in accordance with 44 U.S.C.3702 (see 5.502(a)).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_5_101__c','FAR_5_101','5.101','Methods of disseminating information.','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information.','(a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), contracting officers must disseminate information on proposed contract actions as follows: (b) In addition, one or more of the following methods may be used:','Part 5 › Subpart 5.1 › 5.101 Methods of disseminating information. | (a) As required by the Small Business Act (15 U.S.C. 637(e)) and the Office of Federal Procurement Policy Act (41 U.S.C. 1708), contracting officers must disseminate information on proposed contract actions as follows: (b) In addition, one or more of the following methods may be used:');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_6_302_2_a__c','FAR_6_302_2_a','6.302-2(a)','Unusual and compelling urgency.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (a)','(a) Authority. (1) Citations: 10 U.S.C. 3204(a)(2) or 41 U.S.C. 3304(a)(2). (2) When the agency’s need for the supplies or services is of such an unusual and compelling urgency that the Government would be seriously injured unless the agency is permitted to limit the number of sources from which it solicits bids or proposals, full and open competition need not be provided for.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (a) | (a) Authority. (1) Citations: 10 U.S.C. 3204(a)(2) or 41 U.S.C. 3304(a)(2). (2) When the agency’s need for the supplies or services is of such an unusual and compelling urgency that the Government would be seriously injured unless the agency is permitted to limit the number of sources from which it solicits bids or proposals, full and open competition need not be provided for.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_6_302_2_b__c','FAR_6_302_2_b','6.302-2(b)','Unusual and compelling urgency.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (b)','(b) Application. This authority applies in those situations where- (1) An unusual and compelling urgency precludes full and open competition; and (2) Delay in award of a contract would result in serious injury, financial or other, to the Government.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (b) | (b) Application. This authority applies in those situations where- (1) An unusual and compelling urgency precludes full and open competition; and (2) Delay in award of a contract would result in serious injury, financial or other, to the Government.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_6_302_2_c__c','FAR_6_302_2_c','6.302-2(c)','Unusual and compelling urgency.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (c)','(c) Limitations. (1) Contracts awarded using this authority shall be supported by the written justifications and approvals described in 6.303 and 6.304. These justifications may be made and approved after contract award when preparation and approval prior to award would unreasonably delay the acquisition. (2) This statutory authority requires that agencies shall request offers from as many potential sources as is practicable under the circumstances.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (c) | (c) Limitations. (1) Contracts awarded using this authority shall be supported by the written justifications and approvals described in 6.303 and 6.304. These justifications may be made and approved after contract award when preparation and approval prior to award would unreasonably delay the acquisition. (2) This statutory authority requires that agencies shall request offers from as many potential sources as is practicable under the circumstances.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_6_302_2_d__c','FAR_6_302_2_d','6.302-2(d)','Unusual and compelling urgency.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (d)','(d) Period of Performance. (1) The total period of performance of a contract awarded or modified using this authority- (i) May not exceed the time necessary- (A) To meet the unusual and compelling requirements of the work to be performed under the contract; and (B) For the agency to enter into another contract for the required goods and services through the use of competitive procedures; and (ii) May not exceed one year, including all options, unless the head of the agency determines that exceptional circumstances apply. This determination must be documented in the contract file. (i) Any subsequent modification using this authority, which will extend the period of performance beyond one year under this same authority, requires a separate determination. This determination is only required if the cumulative period of performance using this authority exceeds one year. This requirement does not apply to the exercise of options previously addressed in the determination required at paragraph (d)(1)(ii) of this section. (ii) The determination shall be approved at the same level as the level to which the agency head authority in paragraph (d)(1)(ii)of this section is delegated. (3) The requirements in paragraphs (d)(1) and (2) of this section shall apply to any contract in an amount greater than the simplified acquisition threshold. (4) The determination of exceptional circumstances is in addition to the approval of the justification in 6.304. (5) The determination may be made after contract award when making the determination prior to award would unreasonably delay the acquisition.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. › (d) | (d) Period of Performance. (1) The total period of performance of a contract awarded or modified using this authority- (i) May not exceed the time necessary- (A) To meet the unusual and compelling requirements of the work to be performed under the contract; and (B) For the agency to enter into another contract for the required goods and services through the use of competitive procedures; and (ii) May not exceed one year, including all options, unless the head of the agency determines that exceptional circumstances apply. This determination must be documented in the contract file. (i) Any subsequent modification using this authority, which will extend the period of performance beyond one year under this same authority, requires a separate determination. This determination is only required if the cumulative period of performance using this authority exceeds one year. This requirement does not apply to the exercise of options previously addressed in the determination required at paragraph (d)(1)(ii) of this section. (ii) The determination shall be approved at the same level as the level to which the agency head authority in paragraph (d)(1)(ii)of this section is delegated. (3) The requirements in paragraphs (d)(1) and (2) of this section shall apply to any contract in an amount greater than the simplified acquisition threshold. (4) The determination of exceptional circumstances is in addition to the approval of the justification in 6.304. (5) The determination may be made after contract award when making the determination prior to award would unreasonably delay the acquisition.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_6_302_2__c','FAR_6_302_2','6.302-2','Unusual and compelling urgency.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency.','(a) Authority. (b) Application. This authority applies in those situations where- (c) Limitations. (d) Period of Performance.','Part 6 › Subpart 6.3 › 6.302-2 Unusual and compelling urgency. | (a) Authority. (b) Application. This authority applies in those situations where- (c) Limitations. (d) Period of Performance.');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_16_505_a__c','FAR_16_505_a','16.505(a)','Ordering.','Part 16 › Subpart 16.5 › 16.505 Ordering. › (a)','(a) General. (1) In general, the contracting officer does not synopsize orders under indefinite-delivery contracts; except see 16.505(a)(4) and (11), and 16.505(b)(2)(ii)(D). (2) Individual orders shall clearly describe all services to be performed or supplies to be delivered so the full cost or price for the performance of the work can be established when the order is placed. Orders shall be within the scope, issued within the period of performance, and be within the maximum value of the contract. (3) Performance-based acquisition methods must be used to the maximum extent practicable, if the contract or order is for services (see 37.102(a) and subpart 37.6). (4) The following requirements apply when procuring items peculiar to one manufacturer: (i) The contracting officer must justify restricting consideration to an item peculiar to one manufacturer (e.g., a particular brand-name, product, or a feature of a product that is peculiar to one manufacturer). A brand-name item, even if available on more than one contract, is an item peculiar to one manufacturer. Brand-name specifications shall not be used unless the particular brand-name, product, or feature is essential to the Government’s requirements and market research indicates other companies’ similar products, or products lacking the particular feature, do not meet, or cannot be modified to meet, the agency’s needs. (ii) Requirements for use of items peculiar to one manufacturer shall be justified and approved using the format(s) and requirements from paragraphs (b)(2)(ii)(A), (B), and (C) of this section, modified to show the brand-name justification. A justification is required unless a justification covering the requirements in the order was previously approved for the contract in accordance with 6.302-1(c) or unless the base contract is a single-award contract awarded under full and open competition. Justifications for the use of brand-name specifications must be completed and approved at the time the requirement for a brand-name is determined. (A) For an order in excess of $40,000, the contracting officer shall— (1) Post the justification and supporting documentation on the agency website used (if any) to solicit offers for orders under the contract; or (2) Provide the justification and supporting documentation along with the solicitation to all contract awardees. (B) The justifications for brand-name acquisitions may apply to the portion of the acquisition requiring the brand-name item. If the justification is to cover only the portion of the acquisition which is brand-name, then it should so state; the approval level requirements will then only apply to that portion. (C) The requirements in paragraph (a)(4)(iii)(A) of this section do not apply when disclosure would compromise the national security (e.g., would result in disclosure of classified information) or create other security risks. (D) The justification is subject to the screening requirement in paragraph (b)(2)(ii)(D)(4) of this section. (5) When acquiring information technology and related services, consider the use of modular contracting to reduce program risk (see 39.103(a)). (6) Orders may be placed by using any medium specified in the contract. (7) Orders placed under indefinite-delivery contracts must contain the following information: (i) Date of order. (ii) Contract number and order number. (iii) For supplies and services, line item number, subline item number (if applicable), description, quantity, and unit price or estimated cost and fee (as applicable). The corresponding line item number and subline item number from the base contract shall also be included. (iv) Delivery or performance schedule. (v) Place of delivery or performance (including consignee). (vi) Any packaging, packing, and shipping instructions. (vii) Accounting and appropriation data. (viii) Method of payment and payment office, if not specified in the contract (see 32.1110(e)). (ix) North American Industry Classification System code (see 19.102(b)(3)). (8) Orders placed under a task-order contract or delivery-order contract awarded by another agency (i.e.,a Governmentwide acquisition contract, or multi-agency contract)— (i) Are not exempt from the development of acquisition plans (see subpart 7.1), and an information technology acquisition strategy (see part 39); (ii) May not be used to circumvent conditions and limitations imposed on the use of funds (e.g., 31 U.S.C. 1501(a)(1)); and (iii) Shall comply with all FAR requirements for a consolidated or bundled contract when the order meets the definition at 2.101 of "consolidation" or "bundling". (9) In accordance with section 1427(b) of Public Law 108-136 (40 U.S.C. 1103 note), orders placed under multi-agency contracts for services that substantially or to a dominant extent specify performance of architect-engineer services, as defined in 2.101, shall— (i) Be awarded using the procedures at subpart 36.6; and (ii) Require the direct supervision of a professional architect or engineer licensed, registered or certified in the State, Federal District, or outlying area, in which the services are to be performed. (i) No protest under subpart 33.1 is authorized in connection with the issuance or proposed issuance of an order under a task-order contract or delivery-order contract, except— (A) A protest on the grounds that the order increases the scope, period, or maximum value of the contract; or (1) For agencies other than DoD, NASA, and the Coast Guard, a protest of an order valued in excess of $10 million (41 U.S.C. 4106(f)); or (2) For DoD, NASA, or the Coast Guard, a protest of an order valued in excess of $25 million (10 U.S.C. 3406(f)). (ii) Protests of orders in excess of the thresholds stated in 16.505(a)(10)(i)(B) may only be filed with the Government Accountability Office, in accordance with the procedures at 33.104. (iii) For protests of small business size status for set-aside orders, see 19.302. (11) Publicize orders funded in whole or in part by the American Recovery and Reinvestment Act of 2009 (Pub. L. 111-5) as follows: (i) Notices of proposed orders shall follow the procedures in 5.704 for posting orders. (ii) Award notices for orders shall follow the procedures in 5.705. (12) When using the Governmentwide commercial purchase card as a method of payment, orders at or below the micro-purchase threshold are exempt from verification in the System for Award Management as to whether the contractor has a delinquent debt subject to collection under the Treasury Offset Program (TOP).','Part 16 › Subpart 16.5 › 16.505 Ordering. › (a) | (a) General. (1) In general, the contracting officer does not synopsize orders under indefinite-delivery contracts; except see 16.505(a)(4) and (11), and 16.505(b)(2)(ii)(D). (2) Individual orders shall clearly describe all services to be performed or supplies to be delivered so the full cost or price for the performance of the work can be established when the order is placed. Orders shall be within the scope, issued within the period of performance, and be within the maximum value of the contract. (3) Performance-based acquisition methods must be used to the maximum extent practicable, if the contract or order is for services (see 37.102(a) and subpart 37.6). (4) The following requirements apply when procuring items peculiar to one manufacturer: (i) The contracting officer must justify restricting consideration to an item peculiar to one manufacturer (e.g., a particular brand-name, product, or a feature of a product that is peculiar to one manufacturer). A brand-name item, even if available on more than one contract, is an item peculiar to one manufacturer. Brand-name specifications shall not be used unless the particular brand-name, product, or feature is essential to the Government’s requirements and market research indicates other companies’ similar products, or products lacking the particular feature, do not meet, or cannot be modified to meet, the agency’s needs. (ii) Requirements for use of items peculiar to one manufacturer shall be justified and approved using the format(s) and requirements from paragraphs (b)(2)(ii)(A), (B), and (C) of this section, modified to show the brand-name justification. A justification is required unless a justification covering the requirements in the order was previously approved for the contract in accordance with 6.302-1(c) or unless the base contract is a single-award contract awarded under full and open competition. Justifications for the use of brand-name specifications must be completed and approved at the time the requirement for a brand-name is determined. (A) For an order in excess of $40,000, the contracting officer shall— (1) Post the justification and supporting documentation on the agency website used (if any) to solicit offers for orders under the contract; or (2) Provide the justification and supporting documentation along with the solicitation to all contract awardees. (B) The justifications for brand-name acquisitions may apply to the portion of the acquisition requiring the brand-name item. If the justification is to cover only the portion of the acquisition which is brand-name, then it should so state; the approval level requirements will then only apply to that portion. (C) The requirements in paragraph (a)(4)(iii)(A) of this section do not apply when disclosure would compromise the national security (e.g., would result in disclosure of classified information) or create other security risks. (D) The justification is subject to the screening requirement in paragraph (b)(2)(ii)(D)(4) of this section. (5) When acquiring information technology and related services, consider the use of modular contracting to reduce program risk (see 39.103(a)). (6) Orders may be placed by using any medium specified in the contract. (7) Orders placed under indefinite-delivery contracts must contain the following information: (i) Date of order. (ii) Contract number and order number. (iii) For supplies and services, line item number, subline item number (if applicable), description, quantity, and unit price or estimated cost and fee (as applicable). The corresponding line item number and subline item number from the base contract shall also be included. (iv) Delivery or performance schedule. (v) Place of delivery or performance (including consignee). (vi) Any packaging, packing, and shipping instructions. (vii) Accounting and appropriation data. (viii) Method of payment and payment office, if not specified in the contract (see 32.1110(e)). (ix) North American Industry Classification System code (see 19.102(b)(3)). (8) Orders placed under a task-order contract or delivery-order contract awarded by another agency (i.e.,a Governmentwide acquisition contract, or multi-agency contract)— (i) Are not exempt from the development of acquisition plans (see subpart 7.1), and an information technology acquisition strategy (see part 39); (ii) May not be used to circumvent conditions and limitations imposed on the use of funds (e.g., 31 U.S.C. 1501(a)(1)); and (iii) Shall comply with all FAR requirements for a consolidated or bundled contract when the order meets the definition at 2.101 of "consolidation" or "bundling". (9) In accordance with section 1427(b) of Public Law 108-136 (40 U.S.C. 1103 note), orders placed under multi-agency contracts for services that substantially or to a dominant extent specify performance of architect-engineer services, as defined in 2.101, shall— (i) Be awarded using the procedures at subpart 36.6; and (ii) Require the direct supervision of a professional architect or engineer licensed, registered or certified in the State, Federal District, or outlying area, in which the services are to be performed. (i) No protest under subpart 33.1 is authorized in connection with the issuance or proposed issuance of an order under a task-order contract or delivery-order contract, except— (A) A protest on the grounds that the order increases the scope, period, or maximum value of the contract; or (1) For agencies other than DoD, NASA, and the Coast Guard, a protest of an order valued in excess of $10 million (41 U.S.C. 4106(f)); or (2) For DoD, NASA, or the Coast Guard, a protest of an order valued in excess of $25 million (10 U.S.C. 3406(f)). (ii) Protests of orders in excess of the thresholds stated in 16.505(a)(10)(i)(B) may only be filed with the Government Accountability Office, in accordance with the procedures at 33.104. (iii) For protests of small business size status for set-aside orders, see 19.302. (11) Publicize orders funded in whole or in part by the American Recovery and Reinvestment Act of 2009 (Pub. L. 111-5) as follows: (i) Notices of proposed orders shall follow the procedures in 5.704 for posting orders. (ii) Award notices for orders shall follow the procedures in 5.705. (12) When using the Governmentwide commercial purchase card as a method of payment, orders at or below the micro-purchase threshold are exempt from verification in the System for Award Management as to whether the contractor has a delinquent debt subject to collection under the Treasury Offset Program (TOP).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_16_505_b__c','FAR_16_505_b','16.505(b)','Ordering.','Part 16 › Subpart 16.5 › 16.505 Ordering. › (b)','(b) Orders under multiple-award contracts— (1) Fair opportunity. (i) The contracting officer must provide each awardee a fair opportunity to be considered for each order exceeding the micro-purchase threshold issued under multiple delivery-order contracts or multiple task-order contracts, except— (A) As provided for in paragraph (b)(2) of this section; or (B) Orders issued under 19.504(c)(1)(ii). (ii) The contracting officer may exercise broad discretion in developing appropriate order placement procedures. The contracting officer should keep submission requirements to a minimum. Contracting officers may use streamlined procedures, including oral presentations. If the order does not exceed the simplified acquisition threshold, the contracting officer need not contact each of the multiple awardees under the contract before selecting an order awardee if the contracting officer has information available to ensure that each awardee is provided a fair opportunity to be considered for each order. The competition requirements in part 6 and the policies in subpart 15.3 do not apply to the ordering process. However, the contracting officer shall— (A) Develop placement procedures that will provide each awardee a fair opportunity to be considered for each order and that reflect the requirement and other aspects of the contracting environment; (B) Not use any method (such as allocation or designation of any preferred awardee) that would not result in fair consideration being given to all awardees prior to placing each order; (C) Tailor the procedures to each acquisition; (D) Include the procedures in the solicitation and the contract; (E) Consider price or cost under each order as one of the factors in the selection decision; (F) Except for DoD, ensure the criteria at 15.101-2(c)(1)-(5) are met when using the lowest price technically acceptable source selection process; and (G) Except for DoD, avoid using the lowest price technically acceptable source selection process to acquire certain supplies and services in accordance with 15.101-2(d). (iii) Orders exceeding the simplified acquisition threshold. (A) Each order exceeding the simplified acquisition threshold shall be placed on a competitive basis in accordance with paragraph (b)(1)(iii)(B) of this section, unless supported by a written determination that one of the circumstances described at 16.505(b)(2)(i) applies to the order and the requirement is waived on the basis of a justification that is prepared in accordance with 16.505(b)(2)(ii)(B); (B) The contracting officer shall— (1) Provide a fair notice of the intent to make a purchase, including a clear description of the supplies to be delivered or the services to be performed and the basis upon which the selection will be made to all contractors offering the required supplies or services under the multiple-award contract; and (2) Afford all contractors responding to the notice a fair opportunity to submit an offer and have that offer fairly considered. (iv) Orders exceeding $7.5 million. For task or delivery orders in excess of $7.5 million, the requirement to provide all awardees a fair opportunity to be considered for each order shall include, at a minimum— (A) A notice of the task or delivery order that includes a clear statement of the agency’s requirements; (B) A reasonable response period; (C) Disclosure of the significant factors and subfactors, including cost or price, that the agency expects to consider in evaluating proposals, and their relative importance; (D) Where award is made on a best value basis, a written statement documenting the basis for award and the relative importance of quality and price or cost factors; and (E) An opportunity for a postaward debriefing in accordance with paragraph (b)(6) of this section. (v) The contracting officer should consider the following when developing the procedures: (1) Past performance on earlier orders under the contract, including quality, timeliness and cost control. (2) Potential impact on other orders placed with the contractor. (3) Minimum order requirements. (4) The amount of time contractors need to make informed business decisions on whether to respond to potential orders. (5) Whether contractors could be encouraged to respond to potential orders by outreach efforts to promote exchanges of information, such as— (i) Seeking comments from two or more contractors on draft statements of work; (ii) Using a multiphased approach when effort required to respond to a potential order may be resource intensive (e.g., requirements are complex or need continued development), where all contractors are initially considered on price considerations (e.g., rough estimates), and other considerations as appropriate (e.g.,proposed conceptual approach, past performance). The contractors most likely to submit the highest value solutions are then selected for one-on-one sessions with the Government to increase their understanding of the requirements, provide suggestions for refining requirements, and discuss risk reduction measures. (B) Formal evaluation plans or scoring of quotes or offers are not required. (2) Exceptions to the fair opportunity process. (i) The contracting officer shall give every awardee a fair opportunity to be considered for a delivery order or task order exceeding the micro-purchase threshold unless one of the following statutory exceptions applies: (A) The agency need for the supplies or services is so urgent that providing a fair opportunity would result in unacceptable delays. (B) Only one awardee is capable of providing the supplies or services required at the level of quality required because the supplies or services ordered are unique or highly specialized. (C) The order must be issued on a sole-source basis in the interest of economy and efficiency because it is a logical follow-on to an order already issued under the contract, provided that all awardees were given a fair opportunity to be considered for the original order. (D) It is necessary to place an order to satisfy a minimum guarantee. (E) For orders exceeding the simplified acquisition threshold, a statute expressly authorizes or requires that the purchase be made from a specified source. (F) In accordance with section 1331 of Public Law 111-240 (15 U.S.C. 644(r)), contracting officers may, at their discretion, set aside orders for any of the small business concerns identified in 19.000(a)(3). When setting aside orders for small business concerns, the specific small business program eligibility requirements identified in part 19 apply. (G) For DoD, NASA, and the Coast Guard, the order satisfies one of the exceptions permitting the use of other than full and open competition listed in 6.302 (10 U.S.C. 3406(c)(5)). The public interest exception shall not be used unless Congress is notified in accordance with 10 U.S.C. 3204(a)(7). (ii) The justification for an exception to fair opportunity shall be in writing as specified in paragraph (b)(2)(ii)(A) or (B) of this section. No justification is needed for the exception described in paragraph (b)(2)(i)(F) of this section. (A) Orders exceeding the micro-purchase threshold, but not exceeding the simplified acquisition threshold. The contracting officer shall document the basis for using an exception to the fair opportunity process. If the contracting officer uses the logical follow-on exception, the rationale shall describe why the relationship between the initial order and the follow-on is logical (e.g., in terms of scope, period of performance, or value). (B) Orders exceeding the simplified acquisition threshold. As a minimum, each justification shall include the following information and be approved in accordance with paragraph (b)(2)(ii)(C) of this section: (1) Identification of the agency and the contracting activity, and specific identification of the document as a "Justification for an Exception to Fair Opportunity." (2) Nature and/or description of the action being approved. (3) A description of the supplies or services required to meet the agency’s needs (including the estimated value). (4) Identification of the exception to fair opportunity (see 16.505(b)(2)) and the supporting rationale, including a demonstration that the proposed contractor’s unique qualifications or the nature of the acquisition requires use of the exception cited. If the contracting officer uses the logical follow-on exception, the rationale shall describe why the relationship between the initial order and the follow-on is logical (e.g., in terms of scope, period of performance, or value). (5) A determination by the contracting officer that the anticipated cost to the Government will be fair and reasonable. (6) Any other facts supporting the justification. (7) A statement of the actions, if any, the agency may take to remove or overcome any barriers that led to the exception to fair opportunity before any subsequent acquisition for the supplies or services is made. (8) The contracting officer’s certification that the justification is accurate and complete to the best of the contracting officer’s knowledge and belief. (9) Evidence that any supporting data that is the responsibility of technical or requirements personnel (e.g., verifying the Government’s minimum needs or requirements or other rationale for an exception to fair opportunity) and which form a basis for the justification have been certified as complete and accurate by the technical or requirements personnel. (10) A written determination by the approving official that one of the circumstances in paragraphs (b)(2)(i)(A) through (E) and (G) of this section applies to the order. (C) Approval. (1) For proposed orders exceeding the simplified acquisition threshold, but not exceeding $900,000, the ordering activity contracting officer''s certification that the justification is accurate and complete to the best of the ordering activity contracting officer''s knowledge and belief will serve as approval, unless a higher approval level is established in accordance with agency procedures. (2) For a proposed order exceeding $900,000, but not exceeding $20 million, the justification must be approved by the advocate for competition of the activity placing the order, or by an official named in paragraph (b)(2)(ii)(C)( 3) or ( 4) of this section. This authority is not delegable. (3) For a proposed order exceeding $20 million, but not exceeding $90 million (or, for DoD, NASA, and the Coast Guard, not exceeding $150 million), the justification must be approved by— (i) The head of the procuring activity placing the order; (ii) A designee who— ( If a member of the armed forces, is a general or flag officer; ( If a civilian, is serving in a position in a grade above GS-15 under the General Schedule (or in a comparable or higher position under another schedule); or (iii) An official named in paragraph (b)(2)(ii)(C)(4)of this section. (4) For a proposed order exceeding $90 million (or, for DoD, NASA, and the Coast Guard, over $150 million), the justification must be approved by the senior procurement executive of the agency placing the order. This authority is not delegable, except in the case of the Under Secretary of Defense for Acquisition and Sustainment, acting as the senior procurement executive for the Department of Defense. (D) Posting. (1) Except as provided in paragraph (b)(2)(ii)(D)(5) of this section, within 14 days after placing an order exceeding the simplified acquisition threshold that does not provide for fair opportunity in accordance with 16.505(b), the contract officer shall— (i) Publish a notice in accordance with 5.301; and (ii) Make publicly available the justification required at of this section. (2) The justification shall be made publicly available— (i) At the GPE https://www.sam.gov; (ii) On the Web site of the agency, which may provide access to the justifications by linking to the GPE; and (iii) Must remain posted for a minimum of 30 days. (3) In the case of an order permitted under paragraph (b)(2)(i)(A) of this section, the justification shall be posted within 30 days after award of the order. (4) Contracting officers shall carefully screen all justifications for contractor proprietary data and remove all such data, and such references and citations as are necessary to protect the proprietary data, before making the justifications available for public inspection. Contracting officers shall also be guided by the exemptions to disclosure of information contained in the Freedom of Information Act (5 U.S.C. 552) and the prohibitions against disclosure in 24.202 in determining whether other data should be removed. Although the submitter notice process set out in Executive Order 12600 "Predisclosure Notification Procedures for Confidential Commercial Information" does not apply, if the justification appears to contain proprietary data, the contracting officer should provide the contractor that submitted the information an opportunity to review the justification for proprietary data before making the justification available for public inspection, redacted as necessary. This process must not prevent or delay the posting of the justification in accordance with the timeframes required in paragraphs (b)(2)(ii)(D)(1) and (3) of this section. (5) The posting requirement of this section does not apply— (i) When disclosure would compromise the national security (e.g., would result in disclosure of classified information) or create other security risks; or (ii) To a small business set-aside under paragraph (b)(2)(i)(F) (3) Pricing orders. If the contract did not establish the price for the supply or service, the contracting officer must establish prices for each order using the policies and methods in subpart 15.4. (4) Cost reimbursement orders. For additional requirements for cost-reimbursement orders, see 16.301-3. (5) Time-and-materials or labor-hour orders. For additional requirements for time-and-materials or labor-hour orders, see 16.601(e). (6) Postaward notices and debriefing of awardees for orders exceeding $7.5 million.The contracting officer shall notify unsuccessful awardees when the total price of a task or delivery order exceeds $7.5 million. (i) The procedures at 15.503(b)(1) shall be followed when providing postaward notification to unsuccessful awardees. (ii) The procedures at 15.506 shall be followed when providing postaward debriefing to unsuccessful awardees. (iii) A summary of the debriefing shall be included in the task or delivery order file. (7) Decision documentation for orders. (i) The contracting officer shall document in the contract file the rationale for placement and price of each order, including the basis for award and the rationale for any tradeoffs among cost or price and non-cost considerations in making the award decision. This documentation need not quantify the tradeoffs that led to the decision. (ii) The contract file shall also identify the basis for using an exception to the fair opportunity process (see paragraph (b)(2) of this section). (iii) Except for DoD, the contracting officer shall document in the contract file a justification for use of the lowest price technically acceptable source selection process, when applicable. (8) Task-order and delivery-order ombudsman. The head of the agency shall designate a task-order and delivery-order ombudsman. The ombudsman must review complaints from contractors and ensure they are afforded a fair opportunity to be considered, consistent with the procedures in the contract. The ombudsman must be a senior agency official who is independent of the contracting officer and may be the agency’s advocate for competition. (9) Small business.The contracting officer should rely on the small business representations at the contract level (but see 19.301-2(b)(3) for order rerepresentations).','Part 16 › Subpart 16.5 › 16.505 Ordering. › (b) | (b) Orders under multiple-award contracts— (1) Fair opportunity. (i) The contracting officer must provide each awardee a fair opportunity to be considered for each order exceeding the micro-purchase threshold issued under multiple delivery-order contracts or multiple task-order contracts, except— (A) As provided for in paragraph (b)(2) of this section; or (B) Orders issued under 19.504(c)(1)(ii). (ii) The contracting officer may exercise broad discretion in developing appropriate order placement procedures. The contracting officer should keep submission requirements to a minimum. Contracting officers may use streamlined procedures, including oral presentations. If the order does not exceed the simplified acquisition threshold, the contracting officer need not contact each of the multiple awardees under the contract before selecting an order awardee if the contracting officer has information available to ensure that each awardee is provided a fair opportunity to be considered for each order. The competition requirements in part 6 and the policies in subpart 15.3 do not apply to the ordering process. However, the contracting officer shall— (A) Develop placement procedures that will provide each awardee a fair opportunity to be considered for each order and that reflect the requirement and other aspects of the contracting environment; (B) Not use any method (such as allocation or designation of any preferred awardee) that would not result in fair consideration being given to all awardees prior to placing each order; (C) Tailor the procedures to each acquisition; (D) Include the procedures in the solicitation and the contract; (E) Consider price or cost under each order as one of the factors in the selection decision; (F) Except for DoD, ensure the criteria at 15.101-2(c)(1)-(5) are met when using the lowest price technically acceptable source selection process; and (G) Except for DoD, avoid using the lowest price technically acceptable source selection process to acquire certain supplies and services in accordance with 15.101-2(d). (iii) Orders exceeding the simplified acquisition threshold. (A) Each order exceeding the simplified acquisition threshold shall be placed on a competitive basis in accordance with paragraph (b)(1)(iii)(B) of this section, unless supported by a written determination that one of the circumstances described at 16.505(b)(2)(i) applies to the order and the requirement is waived on the basis of a justification that is prepared in accordance with 16.505(b)(2)(ii)(B); (B) The contracting officer shall— (1) Provide a fair notice of the intent to make a purchase, including a clear description of the supplies to be delivered or the services to be performed and the basis upon which the selection will be made to all contractors offering the required supplies or services under the multiple-award contract; and (2) Afford all contractors responding to the notice a fair opportunity to submit an offer and have that offer fairly considered. (iv) Orders exceeding $7.5 million. For task or delivery orders in excess of $7.5 million, the requirement to provide all awardees a fair opportunity to be considered for each order shall include, at a minimum— (A) A notice of the task or delivery order that includes a clear statement of the agency’s requirements; (B) A reasonable response period; (C) Disclosure of the significant factors and subfactors, including cost or price, that the agency expects to consider in evaluating proposals, and their relative importance; (D) Where award is made on a best value basis, a written statement documenting the basis for award and the relative importance of quality and price or cost factors; and (E) An opportunity for a postaward debriefing in accordance with paragraph (b)(6) of this section. (v) The contracting officer should consider the following when developing the procedures: (1) Past performance on earlier orders under the contract, including quality, timeliness and cost control. (2) Potential impact on other orders placed with the contractor. (3) Minimum order requirements. (4) The amount of time contractors need to make informed business decisions on whether to respond to potential orders. (5) Whether contractors could be encouraged to respond to potential orders by outreach efforts to promote exchanges of information, such as— (i) Seeking comments from two or more contractors on draft statements of work; (ii) Using a multiphased approach when effort required to respond to a potential order may be resource intensive (e.g., requirements are complex or need continued development), where all contractors are initially considered on price considerations (e.g., rough estimates), and other considerations as appropriate (e.g.,proposed conceptual approach, past performance). The contractors most likely to submit the highest value solutions are then selected for one-on-one sessions with the Government to increase their understanding of the requirements, provide suggestions for refining requirements, and discuss risk reduction measures. (B) Formal evaluation plans or scoring of quotes or offers are not required. (2) Exceptions to the fair opportunity process. (i) The contracting officer shall give every awardee a fair opportunity to be considered for a delivery order or task order exceeding the micro-purchase threshold unless one of the following statutory exceptions applies: (A) The agency need for the supplies or services is so urgent that providing a fair opportunity would result in unacceptable delays. (B) Only one awardee is capable of providing the supplies or services required at the level of quality required because the supplies or services ordered are unique or highly specialized. (C) The order must be issued on a sole-source basis in the interest of economy and efficiency because it is a logical follow-on to an order already issued under the contract, provided that all awardees were given a fair opportunity to be considered for the original order. (D) It is necessary to place an order to satisfy a minimum guarantee. (E) For orders exceeding the simplified acquisition threshold, a statute expressly authorizes or requires that the purchase be made from a specified source. (F) In accordance with section 1331 of Public Law 111-240 (15 U.S.C. 644(r)), contracting officers may, at their discretion, set aside orders for any of the small business concerns identified in 19.000(a)(3). When setting aside orders for small business concerns, the specific small business program eligibility requirements identified in part 19 apply. (G) For DoD, NASA, and the Coast Guard, the order satisfies one of the exceptions permitting the use of other than full and open competition listed in 6.302 (10 U.S.C. 3406(c)(5)). The public interest exception shall not be used unless Congress is notified in accordance with 10 U.S.C. 3204(a)(7). (ii) The justification for an exception to fair opportunity shall be in writing as specified in paragraph (b)(2)(ii)(A) or (B) of this section. No justification is needed for the exception described in paragraph (b)(2)(i)(F) of this section. (A) Orders exceeding the micro-purchase threshold, but not exceeding the simplified acquisition threshold. The contracting officer shall document the basis for using an exception to the fair opportunity process. If the contracting officer uses the logical follow-on exception, the rationale shall describe why the relationship between the initial order and the follow-on is logical (e.g., in terms of scope, period of performance, or value). (B) Orders exceeding the simplified acquisition threshold. As a minimum, each justification shall include the following information and be approved in accordance with paragraph (b)(2)(ii)(C) of this section: (1) Identification of the agency and the contracting activity, and specific identification of the document as a "Justification for an Exception to Fair Opportunity." (2) Nature and/or description of the action being approved. (3) A description of the supplies or services required to meet the agency’s needs (including the estimated value). (4) Identification of the exception to fair opportunity (see 16.505(b)(2)) and the supporting rationale, including a demonstration that the proposed contractor’s unique qualifications or the nature of the acquisition requires use of the exception cited. If the contracting officer uses the logical follow-on exception, the rationale shall describe why the relationship between the initial order and the follow-on is logical (e.g., in terms of scope, period of performance, or value). (5) A determination by the contracting officer that the anticipated cost to the Government will be fair and reasonable. (6) Any other facts supporting the justification. (7) A statement of the actions, if any, the agency may take to remove or overcome any barriers that led to the exception to fair opportunity before any subsequent acquisition for the supplies or services is made. (8) The contracting officer’s certification that the justification is accurate and complete to the best of the contracting officer’s knowledge and belief. (9) Evidence that any supporting data that is the responsibility of technical or requirements personnel (e.g., verifying the Government’s minimum needs or requirements or other rationale for an exception to fair opportunity) and which form a basis for the justification have been certified as complete and accurate by the technical or requirements personnel. (10) A written determination by the approving official that one of the circumstances in paragraphs (b)(2)(i)(A) through (E) and (G) of this section applies to the order. (C) Approval. (1) For proposed orders exceeding the simplified acquisition threshold, but not exceeding $900,000, the ordering activity contracting officer''s certification that the justification is accurate and complete to the best of the ordering activity contracting officer''s knowledge and belief will serve as approval, unless a higher approval level is established in accordance with agency procedures. (2) For a proposed order exceeding $900,000, but not exceeding $20 million, the justification must be approved by the advocate for competition of the activity placing the order, or by an official named in paragraph (b)(2)(ii)(C)( 3) or ( 4) of this section. This authority is not delegable. (3) For a proposed order exceeding $20 million, but not exceeding $90 million (or, for DoD, NASA, and the Coast Guard, not exceeding $150 million), the justification must be approved by— (i) The head of the procuring activity placing the order; (ii) A designee who— ( If a member of the armed forces, is a general or flag officer; ( If a civilian, is serving in a position in a grade above GS-15 under the General Schedule (or in a comparable or higher position under another schedule); or (iii) An official named in paragraph (b)(2)(ii)(C)(4)of this section. (4) For a proposed order exceeding $90 million (or, for DoD, NASA, and the Coast Guard, over $150 million), the justification must be approved by the senior procurement executive of the agency placing the order. This authority is not delegable, except in the case of the Under Secretary of Defense for Acquisition and Sustainment, acting as the senior procurement executive for the Department of Defense. (D) Posting. (1) Except as provided in paragraph (b)(2)(ii)(D)(5) of this section, within 14 days after placing an order exceeding the simplified acquisition threshold that does not provide for fair opportunity in accordance with 16.505(b), the contract officer shall— (i) Publish a notice in accordance with 5.301; and (ii) Make publicly available the justification required at of this section. (2) The justification shall be made publicly available— (i) At the GPE https://www.sam.gov; (ii) On the Web site of the agency, which may provide access to the justifications by linking to the GPE; and (iii) Must remain posted for a minimum of 30 days. (3) In the case of an order permitted under paragraph (b)(2)(i)(A) of this section, the justification shall be posted within 30 days after award of the order. (4) Contracting officers shall carefully screen all justifications for contractor proprietary data and remove all such data, and such references and citations as are necessary to protect the proprietary data, before making the justifications available for public inspection. Contracting officers shall also be guided by the exemptions to disclosure of information contained in the Freedom of Information Act (5 U.S.C. 552) and the prohibitions against disclosure in 24.202 in determining whether other data should be removed. Although the submitter notice process set out in Executive Order 12600 "Predisclosure Notification Procedures for Confidential Commercial Information" does not apply, if the justification appears to contain proprietary data, the contracting officer should provide the contractor that submitted the information an opportunity to review the justification for proprietary data before making the justification available for public inspection, redacted as necessary. This process must not prevent or delay the posting of the justification in accordance with the timeframes required in paragraphs (b)(2)(ii)(D)(1) and (3) of this section. (5) The posting requirement of this section does not apply— (i) When disclosure would compromise the national security (e.g., would result in disclosure of classified information) or create other security risks; or (ii) To a small business set-aside under paragraph (b)(2)(i)(F) (3) Pricing orders. If the contract did not establish the price for the supply or service, the contracting officer must establish prices for each order using the policies and methods in subpart 15.4. (4) Cost reimbursement orders. For additional requirements for cost-reimbursement orders, see 16.301-3. (5) Time-and-materials or labor-hour orders. For additional requirements for time-and-materials or labor-hour orders, see 16.601(e). (6) Postaward notices and debriefing of awardees for orders exceeding $7.5 million.The contracting officer shall notify unsuccessful awardees when the total price of a task or delivery order exceeds $7.5 million. (i) The procedures at 15.503(b)(1) shall be followed when providing postaward notification to unsuccessful awardees. (ii) The procedures at 15.506 shall be followed when providing postaward debriefing to unsuccessful awardees. (iii) A summary of the debriefing shall be included in the task or delivery order file. (7) Decision documentation for orders. (i) The contracting officer shall document in the contract file the rationale for placement and price of each order, including the basis for award and the rationale for any tradeoffs among cost or price and non-cost considerations in making the award decision. This documentation need not quantify the tradeoffs that led to the decision. (ii) The contract file shall also identify the basis for using an exception to the fair opportunity process (see paragraph (b)(2) of this section). (iii) Except for DoD, the contracting officer shall document in the contract file a justification for use of the lowest price technically acceptable source selection process, when applicable. (8) Task-order and delivery-order ombudsman. The head of the agency shall designate a task-order and delivery-order ombudsman. The ombudsman must review complaints from contractors and ensure they are afforded a fair opportunity to be considered, consistent with the procedures in the contract. The ombudsman must be a senior agency official who is independent of the contracting officer and may be the agency’s advocate for competition. (9) Small business.The contracting officer should rely on the small business representations at the contract level (but see 19.301-2(b)(3) for order rerepresentations).');
INSERT INTO chunks (chunk_id,content_item_id,far_address,title,breadcrumb,canonical_text,enriched_text) VALUES ('FAR_16_505_c__c','FAR_16_505_c','16.505(c)','Ordering.','Part 16 › Subpart 16.5 › 16.505 Ordering. › (c)','(c) Limitation on ordering period for task-order contracts for advisory and assistance services. (1) Except as provided for in paragraphs (c)(2) and (3) of this section, the ordering period of a task-order contract for advisory and assistance services, including all options or modifications, normally may not exceed 5 years. (2) The 5-year limitation does not apply when— (i) A longer ordering period is specifically authorized by a statute; or (ii) The contract is for an acquisition of supplies or services that includes the acquisition of advisory and assistance services and the contracting officer, or other official designated by the head of the agency, determines that the advisory and assistance services are incidental and not a significant component of the contract. (3) The contracting officer may extend the contract on a sole-source basis only once for a period not to exceed 6 months if the contracting officer, or other official designated by the head of the agency, determines that— (i) The award of a follow-on contract is delayed by circumstances that were not reasonably foreseeable at the time the initial contract was entered into; and (ii) The extension is necessary to ensure continuity of services, pending the award of the follow-on contract.','Part 16 › Subpart 16.5 › 16.505 Ordering. › (c) | (c) Limitation on ordering period for task-order contracts for advisory and assistance services. (1) Except as provided for in paragraphs (c)(2) and (3) of this section, the ordering period of a task-order contract for advisory and assistance services, including all options or modifications, normally may not exceed 5 years. (2) The 5-year limitation does not apply when— (i) A longer ordering period is specifically authorized by a statute; or (ii) The contract is for an acquisition of supplies or services that includes the acquisition of advisory and assistance services and the contracting officer, or other official designated by the head of the agency, determines that the advisory and assistance services are incidental and not a significant component of the contract. (3) The contracting officer may extend the contract on a sole-source basis only once for a period not to exceed 6 months if the contracting officer, or other official designated by the head of the agency, determines that— (i) The award of a follow-on contract is delayed by circumstances that were not reasonably foreseeable at the time the initial contract was entered into; and (ii) The extension is necessary to ensure continuity of services, pending the award of the follow-on contract.');
